import { readFileSync } from 'node:fs';
import { resolve } from 'node:path';

import { describe, expect, it } from 'vitest';

const serverSource = readFileSync(
  resolve(__dirname, '../src/bin/openai-server.ts'),
  'utf8',
);

describe('openai-server Thoth oath ledger config', () => {
  it('threads THOTH_OATH_LEDGER_PATH into the runtime file ledger store', () => {
    expect(serverSource).toContain("process.env['THOTH_OATH_LEDGER_PATH']");
    expect(serverSource).toContain('createThothOathFileLedgerStore');
    expect(serverSource).toContain('thothOathLedgerStore');
    expect(serverSource).toContain('thoth_oath_ledger');
  });

  it('exposes operator-owned oath CRUD routes outside model mediation', () => {
    expect(serverSource).toContain("url === '/v1/thoth/oaths' && method === 'GET'");
    expect(serverSource).toContain("url === '/v1/thoth/oaths' && method === 'POST'");
    expect(serverSource).toContain("url.startsWith('/v1/thoth/oaths/') && method === 'PATCH'");
    expect(serverSource).toContain("url.startsWith('/v1/thoth/oaths/') && method === 'DELETE'");
    expect(serverSource).toContain('handleThothOathCreate');
    expect(serverSource).toContain('handleThothOathPatch');
    expect(serverSource).toContain('handleThothOathDelete');
  });
});
